      doc.text(`* Melhor Dia do Mes Calendario (1-31): ${allTimeStats.bestDayOfMonth.dayNum} (Media: ${formatCurrency(allTimeStats.bestDayOfMonth.average)} por dia)`, 14, 126);
      
      // Let's add top products if they are available
